/* ============================================================================
   Modern Enhancements for RRI Research Wiki
   ============================================================================ */

/* Root Variables for Modern Design System */
:root {
  --rri-gradient-primary: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  --rri-gradient-accent: linear-gradient(135deg, #f093fb 0%, #f5576c 100%);
  --rri-gradient-secondary: linear-gradient(135deg, #4facfe 0%, #00f2fe 100%);
  --rri-shadow-soft: 0 2px 20px rgba(0,0,0,0.1);
  --rri-shadow-medium: 0 8px 30px rgba(0,0,0,0.12);
  --rri-border-radius: 12px;
  --rri-transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

/* Enhanced Header with Gradient */
.md-header {
  background: var(--rri-gradient-primary) !important;
  backdrop-filter: blur(10px);
  box-shadow: var(--rri-shadow-soft);
}

.md-header__title {
  font-weight: 700;
  background: linear-gradient(45deg, #ffffff, #f0f0f0);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* Modern Navigation Sidebar */
.md-sidebar--primary {
  background: linear-gradient(180deg, 
    rgba(102, 126, 234, 0.05) 0%, 
    rgba(118, 75, 162, 0.05) 100%);
  backdrop-filter: blur(5px);
}

.md-nav__item--active > .md-nav__link {
  background: var(--rri-gradient-accent);
  color: white !important;
  border-radius: var(--rri-border-radius);
  transform: translateX(4px);
  box-shadow: var(--rri-shadow-soft);
  transition: var(--rri-transition);
}

.md-nav__link:hover {
  background: rgba(102, 126, 234, 0.1);
  border-radius: 8px;
  transform: translateX(2px);
  transition: var(--rri-transition);
}

/* Beautiful Content Cards */
.md-content__inner {
  padding: 2rem;
}

.md-typeset h1 {
  background: var(--rri-gradient-primary);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  font-weight: 800;
  margin-bottom: 1.5rem;
  position: relative;
}

.md-typeset h1::after {
  content: '';
  position: absolute;
  bottom: -8px;
  left: 0;
  width: 60px;
  height: 4px;
  background: var(--rri-gradient-accent);
  border-radius: 2px;
}

.md-typeset h2 {
  color: #667eea;
  font-weight: 700;
  margin-top: 2rem;
  margin-bottom: 1rem;
}

/* Modern Code Blocks */
.md-typeset .highlight {
  border-radius: var(--rri-border-radius);
  box-shadow: var(--rri-shadow-soft);
  overflow: hidden;
  margin: 1.5rem 0;
}

.md-typeset .highlight::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  background: var(--rri-gradient-accent);
}

/* Enhanced Admonitions */
.md-typeset .admonition {
  border-radius: var(--rri-border-radius);
  box-shadow: var(--rri-shadow-soft);
  border: none;
  overflow: hidden;
  margin: 1.5rem 0;
  transition: var(--rri-transition);
}

.md-typeset .admonition:hover {
  transform: translateY(-2px);
  box-shadow: var(--rri-shadow-medium);
}

.md-typeset .admonition.info {
  background: linear-gradient(135deg, rgba(79, 172, 254, 0.1), rgba(0, 242, 254, 0.1));
}

.md-typeset .admonition.warning {
  background: linear-gradient(135deg, rgba(255, 193, 7, 0.1), rgba(255, 152, 0, 0.1));
}

.md-typeset .admonition.tip {
  background: linear-gradient(135deg, rgba(76, 175, 80, 0.1), rgba(139, 195, 74, 0.1));
}

/* Beautiful Tables */
.md-typeset table {
  border-radius: var(--rri-border-radius);
  overflow: hidden;
  box-shadow: var(--rri-shadow-soft);
  border: none;
}

.md-typeset table th {
  background: var(--rri-gradient-primary);
  color: white;
  font-weight: 600;
  text-transform: uppercase;
  font-size: 0.85rem;
  letter-spacing: 0.5px;
}

.md-typeset table tr:nth-child(even) {
  background: rgba(102, 126, 234, 0.03);
}

/* Modern Search */
.md-search__form {
  border-radius: 25px;
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.2);
}

.md-search__input {
  background: transparent;
  color: white;
}

.md-search__input::placeholder {
  color: rgba(255, 255, 255, 0.7);
}

/* Floating Action Buttons */
.md-top {
  background: var(--rri-gradient-accent);
  border-radius: 50%;
  box-shadow: var(--rri-shadow-medium);
  transition: var(--rri-transition);
}

.md-top:hover {
  transform: translateY(-2px) scale(1.05);
}

/* Enhanced Footer */
.md-footer {
  background: var(--rri-gradient-primary);
}

.md-footer__inner {
  border-top: 2px solid rgba(255, 255, 255, 0.1);
}

/* Social Links Enhancement */
.md-social__link {
  background: rgba(255, 255, 255, 0.1);
  border-radius: 50%;
  transition: var(--rri-transition);
  margin: 0 4px;
}

.md-social__link:hover {
  background: rgba(255, 255, 255, 0.2);
  transform: translateY(-2px) scale(1.1);
}

/* Custom Animations */
@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.md-content__inner > * {
  animation: fadeInUp 0.6s ease-out;
}

/* Dark Mode Enhancements */
[data-md-color-scheme="slate"] {
  --rri-gradient-primary: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  --rri-gradient-accent: linear-gradient(135deg, #f093fb 0%, #f5576c 100%);
  --rri-shadow-soft: 0 2px 20px rgba(0,0,0,0.3);
  --rri-shadow-medium: 0 8px 30px rgba(0,0,0,0.4);
}

[data-md-color-scheme="slate"] .md-typeset h1 {
  background: linear-gradient(135deg, #667eea 0%, #f093fb 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* Mobile Responsive Enhancements */
@media (max-width: 768px) {
  .md-content__inner {
    padding: 1rem;
  }

  .md-typeset h1 {
    font-size: 1.8rem;
  }
}

/* Cool Hover Effects for Links */
.md-typeset a {
  position: relative;
  transition: var(--rri-transition);
}

.md-typeset a::after {
  content: '';
  position: absolute;
  width: 0;
  height: 2px;
  bottom: -2px;
  left: 0;
  background: var(--rri-gradient-accent);
  transition: width 0.3s ease;
}

.md-typeset a:hover::after {
  width: 100%;
}

/* Enhanced Task Lists */
.md-typeset .task-list-item {
  position: relative;
  list-style: none;
  margin-left: 0;
}

.md-typeset .task-list-control {
  position: absolute;
  left: -1.5rem;
  top: 0.1rem;
}

.md-typeset .task-list-control[checked] + label {
  text-decoration: line-through;
  opacity: 0.6;
}

/* Beautiful Tabs */
.md-typeset .tabbed-set {
  border-radius: var(--rri-border-radius);
  box-shadow: var(--rri-shadow-soft);
  overflow: hidden;
}

.md-typeset .tabbed-labels > label {
  background: linear-gradient(135deg, rgba(102, 126, 234, 0.1), rgba(118, 75, 162, 0.1));
  border-radius: 8px 8px 0 0;
  transition: var(--rri-transition);
}

.md-typeset .tabbed-labels > label:hover {
  background: var(--rri-gradient-primary);
  color: white;
}

/* Loading Animation for Images */
.md-typeset img {
  border-radius: var(--rri-border-radius);
  box-shadow: var(--rri-shadow-soft);
  transition: var(--rri-transition);
}

.md-typeset img:hover {
  transform: scale(1.02);
  box-shadow: var(--rri-shadow-medium);
}

